INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (5, 190804, 1, 10057, 0.0, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", 57, "2021/01/15 12:00:00", "2021/01/24 14:59:59", 1, -416.5, "カリン", 10057005, 0.0);
